import pytest

def test_open_checking_below_minimum_deposit_rejected(
    verified_customer_token, api_client
):
    payload = {"initial_deposit": 24}
    resp = api_client.post(
        "/accounts/checking",
        json=payload,
        headers={"Authorization": f"Bearer {verified_customer_token}"},
    )
    assert resp.status_code == 422
    body = resp.json()
    assert "error" in body or "detail" in body

