def test_open_checking_unverified_customer_forbidden(
    unverified_customer_token, api_client
):
    payload = {"initial_deposit": 1000}
    resp = api_client.post(
        "/accounts/checking",
        json=payload,
        headers={"Authorization": f"Bearer {unverified_customer_token}"},
    )
    assert resp.status_code == 403
    body = resp.json()
    assert "error" in body or "detail" in body
